def solve(arg1: dict) -> list[dict]:
    if 'selector' in arg1:
        # Simulating a database response for roles
        roles = [
            {'id': 1, 'name': 'Admin'},
            {'id': 2, 'name': 'User'}
        ]
        return [{key: role[key] for key in arg1['selector']} for role in roles]

    # Simulating role assignment
    if arg1.get('action') == 'assign':
        user_id = arg1.get('user_id')
        role_id = arg1.get('role_id')
        if user_id and role_id:
            return {'roleId': role_id, 'status': 'assigned'}
        else:
            return {'error': 'User not found'}

    # Simulating role deassignment
    if arg1.get('action') == 'deassign':
        user_id = arg1.get('user_id')
        role_id = arg1.get('role_id')
        if user_id and role_id:
            return {'roleId': role_id, 'status': 'deassigned'}
        else:
            return {'error': 'User not found'}

    # Simulating role check
    if arg1.get('action') == 'has_role':
        user_id = arg1.get('user_id')
        role_id = arg1.get('role_id')
        if user_id and role_id:
            return True
        else:
            return False

    return None
